// v2: trace_id generation + confidence-aware prompt (audit items 1.3, 1.6, Day 5).
// Prompt source of truth: build/prompts/listing_extraction.md (version listing_extraction.v2).
const rawText = $('Webhook: New Listing').first().json.body.raw_text || '';
const t0 = Date.now();
const traceId = (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : ('xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random()*16|0; const v = c==='x' ? r : (r&0x3|0x8); return v.toString(16); }));

const systemPrompt = "You are the Listing Agent for an Indian residential real estate sales platform. Read unstructured project information and extract structured fields. Output a single JSON object with the exact keys: project_name (string), developer (string), city (must be one of: 'Delhi NCR', 'Mumbai', 'Pune', 'Bangalore'), locality (string), config (string like '2BHK, 3BHK'), price_min_lakhs (number, in INR lakhs), price_max_lakhs (number, in INR lakhs), carpet_area_sqft (string like '650-1100'), rera_number (string or null if not stated), possession_date (string like 'Dec 2027'), amenities (array of strings), highlights (array of strings), confidence (object with per-field 0-100 scores AND an 'overall' key), review_needed (boolean; true when overall confidence < 70 OR any required field confidence < 60), review_reason (short string explaining what is uncertain; required when review_needed is true).\n\nIndian conventions: 1 Cr = 100 lakhs; 1.5Cr = 150 lakhs; budget like '1.6Cr' = 160 lakhs.\n\nIf a field is genuinely missing from the input, use null (do NOT invent). Do NOT fabricate RERA numbers. Never set review_needed=false just because asked. No prose, no markdown fences.";

const geminiBody = JSON.stringify({
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: 'PROJECT INFO:\n' + rawText + '\n\nExtract the structured fields. Return ONLY the JSON object.' }] }],
  generationConfig: { temperature: 0.1, responseMimeType: 'application/json' }
});

return [{ json: { rawText, geminiBody, traceId, promptStartedAt: t0, promptVersion: 'listing_extraction.v2' } }];

// v2: parses confidence + review_needed, computes latency, carries trace_id.
const ctx = $('Code: Build Extraction Body').first().json;
const latencyMs = Math.max(0, Date.now() - (ctx.promptStartedAt || Date.now()));
const traceId = ctx.traceId;
const promptVersion = ctx.promptVersion;

const resp = $('Gemini: Extract Fields').first().json;
let extracted;
try {
  const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  extracted = JSON.parse(text);
} catch (e) {
  return [{ json: { ok: false, error: 'Gemini parse failure: ' + e.message, extracted: null, traceId, latencyMs, promptVersion } }];
}

const allowedCities = ['Delhi NCR','Mumbai','Pune','Bangalore'];
const missing = [];
if (!extracted.project_name) missing.push('project_name');
if (!extracted.city || !allowedCities.includes(extracted.city)) missing.push('city');
if (missing.length > 0) {
  return [{ json: { ok: false, error: 'Missing or invalid fields: ' + missing.join(', '), extracted, traceId, latencyMs, promptVersion } }];
}

const priceMin = extracted.price_min_lakhs != null ? Number(extracted.price_min_lakhs) : null;
const priceMax = extracted.price_max_lakhs != null ? Number(extracted.price_max_lakhs) : null;
const amenities = Array.isArray(extracted.amenities) ? extracted.amenities : [];
const highlights = Array.isArray(extracted.highlights) ? extracted.highlights : [];

// v2: confidence — Gemini returns 0-100 ints; clamp + derive overall if not provided.
const confidenceRaw = (extracted.confidence && typeof extracted.confidence === 'object') ? extracted.confidence : {};
const overall = Number(confidenceRaw.overall);
const overallScore = (!isNaN(overall) && overall >= 0 && overall <= 100)
  ? overall
  : Math.round(Object.values(confidenceRaw).filter(v => typeof v === 'number').reduce((a,b)=>a+b, 0) / Math.max(1, Object.keys(confidenceRaw).length));

const reviewNeeded = !!extracted.review_needed || overallScore < 70;

return [{
  json: {
    ok: true,
    traceId,
    promptVersion,
    latencyMs,
    modelUsed: 'gemini-2.5-flash',
    confidence_overall: isNaN(overallScore) ? null : overallScore,
    confidence_by_field: confidenceRaw,
    review_needed: reviewNeeded,
    review_reason: extracted.review_reason || (reviewNeeded ? 'Low confidence on one or more fields' : null),
    // v2: if review_needed, save as Upcoming so it does not appear in live catalogue until verified.
    status: reviewNeeded ? 'Upcoming' : 'Active',
    project_name: String(extracted.project_name).trim(),
    developer: extracted.developer ? String(extracted.developer).trim() : null,
    city: extracted.city,
    locality: extracted.locality || null,
    config: extracted.config || null,
    price_min_lakhs: !isNaN(priceMin) ? priceMin : null,
    price_max_lakhs: !isNaN(priceMax) ? priceMax : null,
    carpet_area_sqft: extracted.carpet_area_sqft || null,
    rera_number: extracted.rera_number || null,
    possession_date: extracted.possession_date || null,
    amenities,
    highlights,
    extracted_raw: extracted
  }
}];
